5	import org.slf4j.LoggerFactory;
6	import org.springframework.beans.factory.annotation.Value;
7	import org.springframework.context.annotation.Bean;
8	import org.springframework.context.annotation.Configuration;
9	
10	@Configuration
11	public class EncryptionConfig {
12	
13	    private static final Logger log = LoggerFactory.getLogger(EncryptionConfig.class);
14	
15	    @Value("${app.encryption-key}")
16	    private String encryptionKey;
17	
18	    private static final String KNOWN_PLACEHOLDER_KEY = "0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef";
19	
20	    @Bean
21	    public EncryptionService encryptionService() {
22	        if (encryptionKey == null || encryptionKey.isBlank()) {
23	            throw new IllegalStateException("app.encryption-key must be configured");
24	        }
25	        if (!encryptionKey.matches("[0-9a-fA-F]+")) {
26	            throw new IllegalStateException("app.encryption-key must be a hex string");
27	        }
28	        if (encryptionKey.length() != 64) {
29	            throw new IllegalStateException(
30	                    "app.encryption-key must be exactly 64 hex characters (32 bytes / 256 bits) for AES-256. Got: "
31	                            + encryptionKey.length() + " characters");
32	        }
33	        if (KNOWN_PLACEHOLDER_KEY.equals(encryptionKey)) {
34	            throw new IllegalStateException(
35	                    "app.encryption-key is set to the default placeholder value. "
36	                            + "Generate a deployment-specific key: openssl rand -hex 32");
37	        }
38	        log.info("AES-256 encryption configured with valid 256-bit key");
39	        return new EncryptionService(encryptionKey);
40	    }
41	}
