11	@Service
12	public class LoginAttemptService {
13	
14	    private final UserRepository userRepository;
15	    private final int maxAttempts;
16	    private final int lockoutDurationMinutes;
17	
18	    public LoginAttemptService(UserRepository userRepository,
19	                               @Value("${app.lockout.max-attempts:5}") int maxAttempts,
20	                               @Value("${app.lockout.duration-minutes:15}") int lockoutDurationMinutes) {
21	        this.userRepository = userRepository;
22	        this.maxAttempts = maxAttempts;
23	        this.lockoutDurationMinutes = lockoutDurationMinutes;
24	    }
25	
26	    @Transactional
27	    public void recordFailedAttempt(User user) {
28	        int newAttempts = user.getFailedAttempts() + 1;
29	        user.setFailedAttempts(newAttempts);
30	
31	        if (newAttempts >= maxAttempts) {
32	            user.setLockoutUntil(LocalDateTime.now().plusMinutes(lockoutDurationMinutes));
33	            user.setStatus(User.UserStatus.LOCKED);
34	        }
35	
36	        userRepository.save(user);
37	    }
38	
39	    public boolean isLocked(User user) {
40	        if (user.getLockoutUntil() == null) {
41	            return false;
42	        }
43	        if (user.getLockoutUntil().isAfter(LocalDateTime.now())) {
44	            return true;
45	        }
46	        // Lockout has expired, reset
47	        resetAttempts(user);
48	        return false;
49	    }
50	
51	    @Transactional
52	    public void resetAttempts(User user) {
53	        user.setFailedAttempts(0);
54	        user.setLockoutUntil(null);
55	        if (user.getStatus() == User.UserStatus.LOCKED) {
56	            user.setStatus(User.UserStatus.ACTIVE);
57	        }
58	        userRepository.save(user);
59	    }
60	}
